const symbol = $.input.stockSymbol || 'AAPL';
const company = $.input.companyName || symbol;
const today = new Date().toISOString().split('T')[0];
const weekAgo = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000).toISOString().split('T')[0];

return {
  newsQuery: symbol + ' ' + company + ' stock news analysis ' + today,
  technicalQuery: symbol + ' stock technical analysis price target support resistance',
  symbol,
  company,
  today,
  weekAgo
};

const newsResp = $.steps.searchNews.response;
const techResp = $.steps.searchTechnical.response;

let newsContent = '';
const newsResults = newsResp.results || newsResp.data || [];
newsResults.slice(0, 8).forEach((r, i) => {
  newsContent += 'NEWS #' + (i + 1) + ':\n';
  newsContent += '  Title: ' + (r.title || 'N/A') + '\n';
  newsContent += '  URL: ' + (r.url || '') + '\n';
  newsContent += '  Content: ' + (r.text || r.content || '').slice(0, 1500) + '\n\n';
});

let techContent = '';
const techResults = techResp.results || techResp.data || [];
techResults.slice(0, 5).forEach((r, i) => {
  techContent += 'TECHNICAL #' + (i + 1) + ':\n';
  techContent += '  Title: ' + (r.title || 'N/A') + '\n';
  techContent += '  Content: ' + (r.text || r.content || '').slice(0, 1500) + '\n\n';
});

return { newsContent, techContent, newsCount: newsResults.length, techCount: techResults.length };

const d = $.steps.compileResearch.output;
const q = $.steps.buildSearchQueries.output;

let prompt = 'You are a senior financial analyst. Create a comprehensive stock analysis report for ' + q.symbol + ' (' + q.company + ') as of ' + q.today + '.

';
prompt += '=== RECENT NEWS (' + d.newsCount + ' articles) ===
' + d.newsContent + '

';
prompt += '=== TECHNICAL ANALYSIS SOURCES (' + d.techCount + ' articles) ===
' + d.techContent + '

';
prompt += 'INSTRUCTIONS:
';
prompt += '- Provide a comprehensive analysis covering: price action, technical indicators (RSI, MACD, support/resistance), news sentiment, and fundamental catalysts
';
prompt += '- Include a clear bull case and bear case
';
prompt += '- Provide actionable trading signals (Buy/Hold/Sell) with confidence level
';
prompt += '- Highlight key upcoming events (earnings, product launches, etc.)
';
prompt += '- DISCLAIMER: This is AI-generated analysis, not financial advice

';
prompt += 'Return ONLY valid JSON:
';
prompt += '{
';
prompt += '  "symbol": "' + q.symbol + '",
';
prompt += '  "company": "' + q.company + '",
';
prompt += '  "date": "' + q.today + '",
';
prompt += '  "overallSignal": "Buy|Hold|Sell",
';
prompt += '  "confidence": "High|Medium|Low",
';
prompt += '  "priceSummary": "current price action summary",
';
prompt += '  "technicalAnalysis": { "rsi": "description", "macd": "description", "support": "level", "resistance": "level", "trend": "Bullish|Bearish|Neutral" },
';
prompt += '  "newsSentiment": { "overall": "Positive|Negative|Neutral", "keyHeadlines": ["headline 1", "headline 2"], "catalysts": ["catalyst 1"] },
';
prompt += '  "bullCase": "why it could go up",
';
prompt += '  "bearCase": "why it could go down",
';
prompt += '  "keyEvents": ["upcoming event 1"],
';
prompt += '  "riskFactors": ["risk 1"],
';
prompt += '  "summary": "2-3 sentence executive summary"
';
prompt += '}';

return { prompt };

let raw = $.steps.aiAnalysis.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { symbol: '', company: '', overallSignal: 'Hold', confidence: 'Low', priceSummary: raw, technicalAnalysis: {}, newsSentiment: {}, bullCase: '', bearCase: '', keyEvents: [], riskFactors: [], summary: raw }; }

const ai = $.steps.parseAI.output;
const q = $.steps.buildSearchQueries.output;

const signalEmoji = ai.overallSignal === 'Buy' ? ':chart_with_upwards_trend:' : ai.overallSignal === 'Sell' ? ':chart_with_downwards_trend:' : ':bar_chart:';

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: q.symbol + ' Stock Analysis Report', emoji: true } });
blocks.push({ type: 'section', fields: [
  { type: 'mrkdwn', text: '*Signal:*\n' + signalEmoji + ' ' + (ai.overallSignal || 'Hold') },
  { type: 'mrkdwn', text: '*Confidence:*\n' + (ai.confidence || 'Medium') },
  { type: 'mrkdwn', text: '*Date:*\n' + q.today },
  { type: 'mrkdwn', text: '*Sentiment:*\n' + ((ai.newsSentiment && ai.newsSentiment.overall) || 'Neutral') }
] });
blocks.push({ type: 'divider' });

const summary = (ai.summary || ai.priceSummary || 'No analysis available.').slice(0, 1800);
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Executive Summary:*\n' + summary } });

if (ai.technicalAnalysis) {
  blocks.push({ type: 'divider' });
  const ta = ai.technicalAnalysis;
  let taText = '*Technical Analysis:*\n';
  if (ta.trend) taText += '  Trend: *' + ta.trend + '*\n';
  if (ta.support) taText += '  Support: ' + ta.support + '\n';
  if (ta.resistance) taText += '  Resistance: ' + ta.resistance + '\n';
  if (ta.rsi) taText += '  RSI: ' + ta.rsi + '\n';
  if (ta.macd) taText += '  MACD: ' + ta.macd + '\n';
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: taText.slice(0, 1800) } });
}

blocks.push({ type: 'divider' });
let caseText = '';
if (ai.bullCase) caseText += '*Bull Case:*\n' + ai.bullCase + '\n\n';
if (ai.bearCase) caseText += '*Bear Case:*\n' + ai.bearCase;
if (caseText) blocks.push({ type: 'section', text: { type: 'mrkdwn', text: caseText.slice(0, 1800) } });

if (ai.newsSentiment && ai.newsSentiment.keyHeadlines && ai.newsSentiment.keyHeadlines.length > 0) {
  blocks.push({ type: 'divider' });
  let hText = '*Key Headlines:*\n';
  ai.newsSentiment.keyHeadlines.slice(0, 5).forEach((h, i) => { hText += (i + 1) + '. ' + h + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: hText.slice(0, 1800) } });
}

if (ai.keyEvents && ai.keyEvents.length > 0) {
  blocks.push({ type: 'divider' });
  let evText = '*Upcoming Events:*\n';
  ai.keyEvents.forEach((ev, i) => { evText += (i + 1) + '. ' + ev + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: evText.slice(0, 1800) } });
}

if (ai.riskFactors && ai.riskFactors.length > 0) {
  let rText = '*Risk Factors:*\n';
  ai.riskFactors.slice(0, 5).forEach((r, i) => { rText += (i + 1) + '. ' + r + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: rText.slice(0, 1800) } });
}

blocks.push({ type: 'divider' });
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: ':warning: AI-generated analysis. Not financial advice. | Powered by Exa + Claude AI | One CLI' }] });

const fallbackText = q.symbol + ' Analysis: ' + (ai.overallSignal || 'Hold') + ' (' + (ai.confidence || 'Medium') + ') - ' + (ai.summary || '').slice(0, 100);
return { blocks, fallbackText };
